import{_ as t,c as o,o as r,a4 as a}from"./chunks/framework.I1cCAST3.js";const d="/assets/host_route_create.BLtdL110.png",p=JSON.parse('{"title":"添加路由器","description":"","frontmatter":{},"headers":[],"relativePath":"docs/hosts/add-router.md","filePath":"docs/hosts/add-router.md"}'),s={name:"docs/hosts/add-router.md"},e=a('<h1 id="添加路由器" tabindex="-1">添加路由器 <a class="header-anchor" href="#添加路由器" aria-label="Permalink to &quot;添加路由器&quot;">​</a></h1><p>将路由器或网络设备（如交换机或防火墙）添加到 Chaterm，以便您可以通过 SSH 与服务器一起管理它们。</p><h2 id="路由器与个人主机的区别" tabindex="-1">路由器与个人主机的区别 <a class="header-anchor" href="#路由器与个人主机的区别" aria-label="Permalink to &quot;路由器与个人主机的区别&quot;">​</a></h2><p>对于运行网络操作系统（如 Cisco、华为等）的硬件设备，请使用 <strong>网络设备/交换机</strong> 类型。这些设备的 shell 行为通常与标准 Linux/Unix 服务器不同，命令集也更为有限。</p><p>对于运行标准操作系统的通用服务器、虚拟机和云实例，请使用 <strong>服务器/个人</strong> 类型。详见 <a href="/docs/hosts/add-personal">添加个人主机</a>。</p><h2 id="前置条件" tabindex="-1">前置条件 <a class="header-anchor" href="#前置条件" aria-label="Permalink to &quot;前置条件&quot;">​</a></h2><p>添加路由器之前，请确保您已准备好：</p><ul><li><strong>Chaterm 已安装</strong> 并正在运行。如果尚未安装，请参阅 <a href="/docs/start/downloads/">下载</a>。</li><li><strong>设备凭据</strong> -- 网络设备的密码或 SSH 私钥。</li><li><strong>设备 IP 地址</strong>（或主机名）和 SSH 端口号（默认 <code>22</code>）。</li><li>网络设备上已 <strong>启用 SSH</strong>。许多路由器和交换机出厂时默认禁用 SSH，请查阅设备文档以启用。</li></ul><h2 id="操作步骤" tabindex="-1">操作步骤 <a class="header-anchor" href="#操作步骤" aria-label="Permalink to &quot;操作步骤&quot;">​</a></h2><p><img src="'+d+'" alt=""></p><ol><li>从左侧边栏打开 <strong>主机管理</strong> 页面。</li><li>点击主机管理页面右上角的 <strong>添加主机</strong> 按钮。</li><li>在打开的 <strong>添加主机</strong> 侧边栏中，将 <strong>设备类型</strong> 设为 <strong>网络设备/交换机</strong>。</li><li>填写下表所述的其余配置项。</li><li>点击 <strong>创建</strong> 保存设备。</li></ol><h2 id="配置项说明" tabindex="-1">配置项说明 <a class="header-anchor" href="#配置项说明" aria-label="Permalink to &quot;配置项说明&quot;">​</a></h2><table tabindex="0"><thead><tr><th>配置项</th><th>说明</th><th>必填</th></tr></thead><tbody><tr><td><strong>设备类型</strong></td><td>选择 <strong>网络设备/交换机</strong> 表示这是路由器、交换机或类似网络设备。</td><td>是</td></tr><tr><td><strong>连接 IP 或地址</strong></td><td>设备的管理 IP 地址或主机名（如 <code>10.0.0.1</code> 或 <code>core-switch.lan</code>）。</td><td>是</td></tr><tr><td><strong>端口</strong></td><td>设备上的 SSH 服务端口，默认值为 <code>22</code>。</td><td>是</td></tr><tr><td><strong>用户名</strong></td><td>设备上配置的 SSH 登录用户名（如 <code>admin</code>、<code>cisco</code>）。</td><td>是</td></tr><tr><td><strong>认证方式</strong></td><td>选择 <strong>密码</strong> 或 <strong>SSH 密钥</strong>。参见下方提示了解详情。</td><td>是</td></tr><tr><td><strong>SSH 代理</strong></td><td>如果网络设备位于隔离的管理 VLAN 或防火墙之后，可配置 SSH 代理通过中间服务器路由连接。直接连接时留空。</td><td>否</td></tr><tr><td><strong>别名</strong></td><td>便于在主机列表中快速识别此设备的显示名称（如 <code>核心交换机 - DC1</code>）。</td><td>是</td></tr><tr><td><strong>分组</strong></td><td>将设备分配到分组以便于管理（如 <code>network</code>、<code>switches</code>、<code>firewalls</code>）。可选择现有分组或输入新名称。</td><td>否</td></tr></tbody></table><h2 id="认证方式说明" tabindex="-1">认证方式说明 <a class="header-anchor" href="#认证方式说明" aria-label="Permalink to &quot;认证方式说明&quot;">​</a></h2><div class="tip custom-block"><p class="custom-block-title">选择认证方式</p><ul><li><strong>密码认证</strong> -- 输入网络设备上配置的 SSH 密码。这是路由器和交换机最常用的方式。</li><li><strong>密钥认证</strong> -- 选择已在 <a href="/docs/manage/keys/">密钥管理</a> 中导入的 SSH 密钥。许多现代网络操作系统支持基于密钥的认证，建议在支持时使用。</li></ul></div><h2 id="相关页面" tabindex="-1">相关页面 <a class="header-anchor" href="#相关页面" aria-label="Permalink to &quot;相关页面&quot;">​</a></h2><ul><li><a href="/docs/hosts/add-personal">添加个人主机</a> -- 添加标准服务器和虚拟机。</li><li><a href="/docs/hosts/add-bastion">添加堡垒机</a> -- 添加企业堡垒机/跳板服务器。</li><li><a href="/docs/hosts/connect">连接到主机</a> -- 了解会话期间可用的终端功能。</li><li><a href="/docs/manage/keys/">密钥管理</a> -- 导入和管理 SSH 密钥。</li></ul>',17),n=[e];function l(i,c,h,g,u,S){return r(),o("div",null,n)}const m=t(s,[["render",l]]);export{p as __pageData,m as default};
